  /// Get color by name (case-insensitive)
  static Color? getColorByName(String name) {
    final lowerName = name.toLowerCase();
    for (final entry in allColors.entries) {
      if (entry.key.toLowerCase() == lowerName) {
        return entry.value;
      }
    }
    return null;
  }
